const aiResponse = $input.first().json;
let parsed;
try {
  const text = aiResponse.text || aiResponse.content || JSON.stringify(aiResponse);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : { error: 'Could not parse' };
} catch (e) {
  parsed = { raw: aiResponse.text, error: e.message };
}

const now = new Date();
const mealId = `meal_${now.getTime()}`;

// Read daily totals from context or start fresh
const dailyCalories = parsed.totals?.calories || 0;
const dailyTarget = 2000;
const sugarToday = parsed.totals?.sugar || 0;
const sugarLimit = 30;

let alertMsg = '';
if (sugarToday > sugarLimit * 0.8) {
  alertMsg = `\n⚠️ Sugar alert: ${sugarToday}g in this meal (daily limit: ${sugarLimit}g)`;
}

const items = (parsed.items || []).map(i => `  ${i.name} (${i.portion}): ${i.calories} kcal`).join('\n');

const response = `🍽️ *Meal Logged!*\n\n` +
  `*Items:*\n${items}\n\n` +
  `*Totals:*\n` +
  `  Calories: ${parsed.totals?.calories || '?'} kcal\n` +
  `  Protein: ${parsed.totals?.protein || '?'}g\n` +
  `  Carbs: ${parsed.totals?.carbs || '?'}g\n` +
  `  Fat: ${parsed.totals?.fat || '?'}g\n` +
  `  Sugar: ${parsed.totals?.sugar || '?'}g\n` +
  `  Fiber: ${parsed.totals?.fiber || '?'}g\n\n` +
  `Health Rating: ${'⭐'.repeat(parsed.health_rating || 3)}\n` +
  (parsed.notes ? `💡 ${parsed.notes}` : '') +
  alertMsg;

return [{
  json: {
    response,
    meal_id: mealId,
    date: now.toISOString().split('T')[0],
    time: now.toTimeString().split(' ')[0],
    meal_type: parsed.meal_type || 'unknown',
    food_items: (parsed.items || []).map(i => i.name).join(', '),
    calories: parsed.totals?.calories || 0,
    protein_g: parsed.totals?.protein || 0,
    carbs_g: parsed.totals?.carbs || 0,
    fat_g: parsed.totals?.fat || 0,
    sugar_g: parsed.totals?.sugar || 0,
    fiber_g: parsed.totals?.fiber || 0,
    image_url: ''
  }
}];
